  "code": "    # Ensure the list has at least two elements
    if len(numbers) < 2:
        raise ValueError("List must contain at least two elements")

    # Initialize variables to track the closest pair
    min_diff = float('inf')
    closest_pair = (numbers[0], numbers[1])

    # Check all pairs of numbers
    for i in range(len(numbers)):
        for j in range(i + 1, len(numbers)):
            diff = abs(numbers[i] - numbers[j])
            if diff < min_diff:
                min_diff = diff
                # Store the pair in ascending order
                closest_pair = tuple(sorted((numbers[i], numbers[j])))

    return closest_pair",
